import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import { Store, Plus } from 'lucide-react';
import ModalNuevaSucursal from './ModalNuevaSucursal';

const Dashboard = () => {
  const navigate = useNavigate();
  const [showModal, setShowModal] = useState(false);
  
  // Estado de locales con carga inicial desde localStorage
  const [locales, setLocales] = useState(() => {
    const guardados = localStorage.getItem('mis-locales');
    return guardados ? JSON.parse(guardados) : [];
  });

  // Guardar en localStorage cada vez que cambien los locales
  useEffect(() => {
    localStorage.setItem('mis-locales', JSON.stringify(locales));
  }, [locales]);

  const agregarSucursal = (datos) => {
    const nuevo = { id: Date.now().toString(), ...datos };
    const actualizada = [...locales, nuevo];
    setLocales(actualizada);
    // Marcamos este como el local actual para publicar
    localStorage.setItem('local-actual', JSON.stringify(nuevo));
    setShowModal(false);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f8fafc' }}>
      
      {/* SIDEBAR */}
      <div style={sidebarStyle}>
        <h2 style={{ marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Store color="#e67e22" /> Mis Locales
        </h2>
        
        <div style={{ flex: 1, overflowY: 'auto' }}>
          {locales.length === 0 ? (
            <p style={{ color: '#94a3b8', textAlign: 'center' }}>No tienes locales creados.</p>
          ) : (
            locales.map(local => (
              <div key={local.id} style={cardStyle}>
                <div style={{ flex: 1 }}>
                  <strong style={{ display: 'block' }}>{local.nombre}</strong>
                  <span style={{ fontSize: '0.75rem', color: '#64748b' }}>
                    {local.zona}, {local.ciudad}
                  </span>
                </div>
                <button 
                  onClick={() => navigate(`/ofertas/${local.id}`)} 
                  style={btnOfertaStyle}
                >
                  Ofertas
                </button>
              </div>
            ))
          )}
        </div>

        <button onClick={() => setShowModal(true)} style={btnNuevaSucursal}>
          <Plus size={20} /> Nueva Sucursal
        </button>
      </div>

      {/* MAPA */}
      <div style={{ flex: 1 }}>
        <MapContainer center={[-26.816, -65.230]} zoom={13} style={{ height: '100%', width: '100%' }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup>
                <strong>{local.nombre}</strong><br/>
                {local.direccion}
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {showModal && (
        <ModalNuevaSucursal 
          onClose={() => setShowModal(false)} 
          onSave={agregarSucursal} 
        />
      )}
    </div>
  );
};

// --- ESTILOS ---
const sidebarStyle = { width: '380px', padding: '25px', background: 'white', borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column' };
const cardStyle = { padding: '15px', background: '#fff9f5', borderRadius: '12px', marginBottom: '12px', display: 'flex', alignItems: 'center', border: '1px solid #ffe8d6' };
const btnOfertaStyle = { background: '#e67e22', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };
const btnNuevaSucursal = { background: '#1e293b', color: 'white', padding: '15px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', fontWeight: 'bold', marginTop: '10px' };

export default Dashboard;
